var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우와~ 역시 대단하세요!","JPN":"わあ～さすがですね！","ENG":"Wow, you were amazing!","TWN":"哇～真是太厲害了！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"과연 경찰청이 단숨에 경정 자리에 꽂아둘 만한 인재다워요!","JPN":"さすが警察庁が一発で警視に任命する人材なだけありますね！","ENG":"No wonder the higher ups wanted to make you a major!","TWN":"真不愧是被警察廳一口氣提拔為警正的人才！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥! 입에 발린 말은 됐어.","JPN":"ふん！　お世辞はいらないわ。","ENG":"Hmpf! Buttering me up won't do you any good.","TWN":"哼！不需要妳拍馬屁。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그보다 당신들은 생각보다 더 엉망이네.","JPN":"それより、あなたたち思ったよりめちゃくちゃね。","ENG":"By the way, you lot are much worse than I thought.","TWN":"話說回來，你們這些傢伙，比我預想得還要糟糕呢。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런 변변찮은 악당들을 대상으로도 고전하다니, 고작 그런 실력으로 지금까지 범죄와 맞서왔다는 거야?","JPN":"こんな雑魚相手に苦戦するなんて、今までその程度の実力で犯罪に立ち向かってきたの？","ENG":"You don't even seem capable of dealing with small-time hoodlums like these. How on earth have you been fighting crimes?","TWN":"對付這些小小歹徒竟然也會陷入苦戰，你們一直以來都是用這種實力打擊犯罪的嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"역시 무능력자들다워. 이 도시가 멸망하지 않은 게 기적이네.","JPN":"さすが無能力者ね。この都市が滅びなかったのが奇跡だわ。","ENG":"Really, you incompetents never cease to disappoint me. It's a miracle that this city hasn't been completely destroyed yet.","TWN":"真不愧是無能力者，這座城市還沒有被歹徒佔領簡直是奇跡。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어...... 아까부터 무능력자라고 하시는데...... 혹시 저 말인가요?","JPN":"あの……さっきから無能力者って言ってますけど……\\nそれって私のことですか？","ENG":"Um... You keep saying incompetent. Are you referring to me, Major?","TWN":"呃……妳剛才開始就在說無能力者……該不會是在說我吧？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그래. 당신은 카운터가 아니잖아?","JPN":"そう。あなたはカウンターじゃないでしょう？","ENG":"I am. You're no Counter.","TWN":"是啊。妳不是制裁者啊？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"전혀 도움이 안되니까 앞으로는 괜히 현장에 참견할 생각 말고 서류 작업이나 해 두라고.","JPN":"全く役に立たないから、現場に首を突っ込まないで\\n書類仕事でもしなさい。","ENG":"You're useless out in the field. So why don't you just stick with a desk job?","TWN":"妳完全幫不上忙，所以也別想要管現場的事了，去做個文書作業吧。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하...... 그게 경정님 지시라면 어쩔 수 없죠.","JPN":"はは……警視様のご指示なら仕方ありませんね。","ENG":"Hah hah... Well, your wish is my command, Major.","TWN":"哈哈…… 既然是警正大人的命令，那就沒辦法了呢。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼 현장 확인은 경정님이 진행하실 건가요?","JPN":"では、現場確認は警視様がおやりになるんですか？","ENG":"Does that mean you'll go investigate the crime scene yourself?","TWN":"那現場確認就由警正大人親自去做嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......현장 확인?","JPN":"……現場確認？","ENG":"What do you mean?","TWN":"……現場確認？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그게 뭐야? 감히 경찰 건물에 쳐들어 온 범죄자를 때려잡는데 그런 게 왜 필요해?!","JPN":"何それ？　警察の建物に侵入した犯罪者を捕まえるのに、\\nなぜそんなことが必要なの？","ENG":"Why? Who needs to investigate anything when we're busy enough beating up criminals who had the gall to raid a police building?!","TWN":"那是什麼？抓住膽敢闖入警察廳的犯罪者，為什麼需要那種東西？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어...... 음...... 왜냐고 물으시면...... 절차니까요?","JPN":"え……うーん……なぜって聞かれますと……\\nそれが決まりだから？","ENG":"Err... Mm... Well... Because it's protocol?","TWN":"呃……嗯……妳問我為什麼……因為這是流程吧？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"혹시...... 경찰 교육은 따로 안 받으셨나요?","JPN":"ひょっとして……警察の基本業務教育は受けてないんですか？","ENG":"Hang on... Have you received any formal police training?","TWN":"妳該不會……沒有受過警察教育吧？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그","JPN":"そ、そんな……","ENG":"W-well...","TWN":"那、那……"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"런 하찮은 일은 경위가 알아서 해! 난 범죄자들을 소탕하는 것만으로도 바쁘니까!","JPN":"そんなくだらないことは警部補がやればいいじゃない！\\n私は犯罪者を掃討するだけで忙しいから！","ENG":"I'll leave those petty details to you! I'm busy enough busting criminal skulls!","TWN":"那種小事就由警衛妳自行處理吧！我光是要掃蕩犯罪者，就已經忙得不可開交了！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 알겠습니다. 저야 항상 하던 일인데요 뭐.","JPN":"はは、わかりました。いつも私がやっていることですからね。","ENG":"Hah hah, yes, ma'am. This is a 365 days a year thing for me.","TWN":"哈哈，我明白了。反正是我一直在做的事情嘛。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};